      "content": "import { getBackoffDelay } from '../retry';

describe('retry backoff jitter', () => {
  it('produces delays in [base * 0.5, base * 1.5) across 100 samples', () => {
    const attempt = 0;
    const base = 1000 * (1 + 2 * attempt);
    const minExpected = base * 0.5;
    const maxExpected = base * 1.5;

    const delays: number[] = [];
    for (let i = 0; i < 100; i++) {
      delays.push(getBackoffDelay(attempt));
    }

    const actualMin = Math.min(...delays);
    const actualMax = Math.max(...delays);

    expect(actualMin).toBeGreaterThanOrEqual(minExpected);
    expect(actualMax).toBeLessThan(maxExpected);
  });
});
